var minOperations = function(nums, queries) {
    const s = nums.slice().sort((a, b) => a - b);
    const n = s.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + s[i];
    const total = prefix[n];
    const res = [];
    for (const q of queries) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (s[mid] <= q) lo = mid + 1; else hi = mid;
        }
        const idx = lo;
        const leftSum = prefix[idx];
        const leftCount = idx;
        const rightSum = total - leftSum;
        const rightCount = n - idx;
        const cost = (q * leftCount - leftSum) + (rightSum - q * rightCount);
        res.push(cost);
    }
    return res;
};
